<?php declare(strict_types=1); namespace App\Http\Controllers\Btaq; use App\Http\Controllers\Controller; use App\Models\{BtaqGroup,BtaqGroupStudent,BtaqMaterial,BtaqSchedule,BtaqSession,BtaqSessionAttendance,BtaqStudentProgress}; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB; final class BtaqSessionController extends Controller{public function mine(){return view('btaq.mine',['groups'=>BtaqGroup::where('teacher_employee_id',auth()->user()?->employee?->id)->orWhere('employee_id',auth()->user()?->employee?->id)->withCount('students')->get(),'sessions'=>BtaqSession::latest()->paginate(10),'schedules'=>BtaqSchedule::where('teacher_employee_id',auth()->user()?->employee?->id)->get()]);} public function index(){return view('btaq.sessions.index',['sessions'=>BtaqSession::latest()->paginate(15)]);} public function create(Request $r){$schedule=BtaqSchedule::find($r->integer('schedule_id'));$group=($schedule?->group) ?: BtaqGroup::first();return view('btaq.sessions.form',['session'=>new BtaqSession,'group'=>$group,'schedule'=>$schedule,'materials'=>BtaqMaterial::where('is_active',true)->get(),'members'=>$group?BtaqGroupStudent::where('btaq_group_id',$group->id)->where('status','active')->get():collect()]);} public function store(Request $r){$s=$this->save($r);return redirect()->route('btaq-sessions.show',$s)->with('status','Jurnal BTAQ disimpan.');} public function show(BtaqSession $btaqSession){return view('btaq.sessions.show',['session'=>$btaqSession]);} public function edit(BtaqSession $btaqSession){abort_if(!in_array($btaqSession->status,['draft','rejected'],true),403);$group=$btaqSession->group;return view('btaq.sessions.form',['session'=>$btaqSession,'group'=>$group,'schedule'=>$btaqSession->schedule,'materials'=>BtaqMaterial::get(),'members'=>BtaqGroupStudent::where('btaq_group_id',$group->id)->where('status','active')->get()]);} public function update(Request $r,BtaqSession $btaqSession){$s=$this->save($r,$btaqSession);return redirect()->route('btaq-sessions.show',$s)->with('status','Jurnal BTAQ diperbarui.');} public function submit(BtaqSession $btaqSession){DB::transaction(function()use($btaqSession){$s=BtaqSession::lockForUpdate()->findOrFail($btaqSession->id);abort_if(!in_array($s->status,['draft','rejected'],true),422);abort_if($s->attendances()->count()===0,422,'Absensi BTAQ wajib diisi.');$s->update(['status'=>'submitted','submitted_at'=>now(),'finalized_by'=>auth()->id(),'finalized_at'=>now()]);activity('btaq')->performedOn($s)->event('btaq.session.submitted')->log('Jurnal BTAQ dikirim');});return back()->with('status','Jurnal BTAQ dikirim.');} public function print(BtaqSession $btaqSession){return view('btaq.sessions.print',['session'=>$btaqSession]);} private function save(Request $r,?BtaqSession $session=null):BtaqSession{return DB::transaction(function()use($r,$session){$d=$r->validate(['btaq_group_id'=>'required|exists:btaq_groups,id','btaq_schedule_id'=>'nullable|exists:btaq_schedules,id','session_date'=>'required|date|before_or_equal:today','meeting_number'=>'nullable|integer','btaq_material_id'=>'nullable|exists:btaq_materials,id','topic'=>'nullable|string','learning_target'=>'nullable|string','learning_activity'=>'nullable|string','learning_method'=>'nullable|string','evaluation'=>'nullable|string','obstacles'=>'nullable|string','follow_up'=>'nullable|string','teacher_notes'=>'nullable|string']);$group=BtaqGroup::findOrFail($d['btaq_group_id']);$d+=['academic_year_id'=>$group->academic_year_id,'semester_id'=>$group->semester_id,'teacher_employee_id'=>$group->teacher_employee_id?:$group->employee_id,'created_by'=>auth()->id(),'updated_by'=>auth()->id(),'status'=>($session?->status) ?: 'draft'];$s=$session?:BtaqSession::where('btaq_schedule_id',$d['btaq_schedule_id']??0)->whereDate('session_date',$d['session_date'])->first();if ($s) { $s->update($d); } else { $s = BtaqSession::create($d); }foreach($r->input('attendances',[]) as $studentId=>$a){$m=BtaqGroupStudent::where('btaq_group_id',$group->id)->where('student_id',$studentId)->where('status','active')->first(); if($m) BtaqSessionAttendance::updateOrCreate(['btaq_session_id'=>$s->id,'student_id'=>$studentId],['btaq_group_student_id'=>$m->id,'status'=>$a['status']??'present','arrival_time'=>$a['arrival_time']??null,'notes'=>$a['notes']??null,'recorded_by'=>auth()->id()]);}foreach($r->input('progress',[]) as $studentId=>$p){if(BtaqGroupStudent::where('btaq_group_id',$group->id)->where('student_id',$studentId)->where('status','active')->exists()) BtaqStudentProgress::updateOrCreate(['btaq_session_id'=>$s->id,'student_id'=>$studentId],['btaq_group_id'=>$group->id,'btaq_program_id'=>$group->btaq_program_id,'current_level_id'=>$group->btaq_level_id,'btaq_material_id'=>$d['btaq_material_id']??null,'reading_reference'=>$p['reading_reference']??null,'achievement_status'=>$p['achievement_status']??'mulai_berkembang','teacher_notes'=>$p['teacher_notes']??null,'next_target'=>$p['next_target']??null,'recorded_by'=>auth()->id(),'recorded_at'=>now()]);}activity('btaq')->performedOn($s)->event('btaq.session.saved')->log('Jurnal BTAQ disimpan');return $s;});}}
